import type { IpcMain } from 'electron'
import { FileStore } from '../../electron/fileStore.js'
import { CHANNELS } from './channels.js'
import type { RootState } from '@core/domain'

const store = new FileStore<RootState>('state.json', {
    root: { id: 'root', name: 'Root', children: [] },
    sharedSteps: []
})

export function registerHandlers(ipcMain: IpcMain) {
    ipcMain.handle(CHANNELS.LOAD_STATE, (_e, fallback: RootState) => {
        try { return store.read() } catch { return fallback }
    })
    ipcMain.handle(CHANNELS.SAVE_STATE, (_e, state: RootState) => {
        store.write(state)
        return true
    })
}
